**KStream — the heart of Kafka Streams:**

```java
import org.apache.kafka.streams.StreamsBuilder;
import org.apache.kafka.streams.kstream.*;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class TradingStreamsTopology {

    @Bean
    public KStream<String, TradeEvent> tradeStream(StreamsBuilder builder) {

        KStream<String, TradeEvent> trades = builder.stream(
            "trade-executed",
            Consumed.with(Serdes.String(), tradeSerde()));

        // FILTER — only BUY trades:
        KStream<String, TradeEvent> buyTrades = trades
            .filter((key, event) -> "BUY".equals(event.type()));

        // MAP — transform the event:
        KStream<String, Double> tradeValues = trades
            .mapValues(event -> event.totalValue());

        // PEEK — log without changing stream:
        trades.peek((key, event) ->
            System.out.printf("Stream: %s %s x%d%n",
                event.type(), event.symbol(), event.qty()));

        // RE-KEY — change the key for grouping:
        KStream<String, TradeEvent> bySymbol = trades
            .selectKey((key, event) -> event.symbol());

        // BRANCH — split stream:
        Map<String, KStream<String, TradeEvent>> branched = trades
            .split(Named.as("branch-"))
            .branch((key, e) -> "BUY".equals(e.type()),  Named.as("buys"))
            .branch((key, e) -> "SELL".equals(e.type()), Named.as("sells"))
            .defaultBranch(Named.as("other"));

        // WRITE to output topic:
        buyTrades.to("buy-trades", Produced.with(Serdes.String(), tradeSerde()));

        return trades;
    }
}

