```java
@Configuration
@EnableKafkaStreams
public class TradeAnalyticsTopology {

    @Bean
    public KStream<String, TradeEvent> analyticsTopology(StreamsBuilder builder) {
        KStream<String, TradeEvent> trades = builder.stream(
            "trade-executed",
            Consumed.with(Serdes.String(), tradeEventSerde()));

        // Branch 1: Large trades (>₹1L) → 'large-trades' topic:
        trades
            .filter((key, e) -> e.totalValue() > 100_000)
            .to("large-trades");

        // Branch 2: Trade count per symbol → 'symbol-trade-count':
        trades
            .selectKey((k, e) -> e.symbol())
            .groupByKey()
            .count(Materialized.as("symbol-count-store"))
            .toStream()
            .to("symbol-trade-count",
                Produced.with(Serdes.String(), Serdes.Long()));

        // Branch 3: 5-min volume per symbol → 'symbol-volume-5min':
        trades
            .selectKey((k, e) -> e.symbol())
            .groupByKey()
            .windowedBy(TimeWindows.ofSizeWithNoGrace(Duration.ofMinutes(5)))
            .aggregate(
                () -> 0.0,
                (sym, e, vol) -> vol + e.totalValue(),
                Materialized.<String, Double, WindowStore<Bytes,byte[]>>
                    as("symbol-5min-vol").withValueSerde(Serdes.Double())
            )
            .toStream()
            .map((windowed, vol) -> KeyValue.pair(windowed.key(), vol))
            .to("symbol-volume-5min",
                Produced.with(Serdes.String(), Serdes.Double()));

        return trades;
    }
}
```

