class TradeAnalyticsTopologyTest {
    TopologyTestDriver driver;
    TestInputTopic<String, TradeEvent> inputTopic;
    TestOutputTopic<String, Long> countTopic;

    @BeforeEach void setup() {
        StreamsBuilder builder = new StreamsBuilder();
        new TradeAnalyticsTopology().analyticsTopology(builder);

        Properties props = new Properties();
        props.put(StreamsConfig.APPLICATION_ID_CONFIG, "test-app");
        props.put(StreamsConfig.BOOTSTRAP_SERVERS_CONFIG, "dummy:9092");

        driver = new TopologyTestDriver(builder.build(), props);
        inputTopic = driver.createInputTopic("trade-executed",
            new StringSerializer(), new JsonSerializer<>());
        countTopic = driver.createOutputTopic("symbol-trade-count",
            new StringDeserializer(), new LongDeserializer());
    }
    @AfterEach void teardown() { driver.close(); }

    @Test void tradeCounts_accumulatePerSymbol() {
        inputTopic.pipeInput("TCS", trade("TCS", 10));
        inputTopic.pipeInput("TCS", trade("TCS", 5));
        inputTopic.pipeInput("INFY", trade("INFY", 3));

        // Count for TCS = 2, INFY = 1:
        var records = countTopic.readKeyValuesToMap();
        assertEquals(2L, records.get("TCS"));
        assertEquals(1L, records.get("INFY"));
    }
}
```

